import logging
import stripe
from models.order import Order
from database import db_session

log = logging.getLogger(__name__)


def process_payment(order_id: int, token: str) -> dict:
    order = Order.query.get(order_id)
    if not order:
        return {'success': False, 'error': 'Order not found'}
    if order.status == 'paid':
        return {'success': True, 'message': 'Already paid'}

    amount_cents = round(order.total * 100)
    try:
        charge = stripe.Charge.create(
            amount=amount_cents,
            currency='usd',
            source=token,
            idempotency_key=f'order-{order_id}',
            metadata={'order_id': str(order_id)}
        )
    except stripe.error.CardError as e:
        log.warning('Card declined for order %d: %s', order_id, e.user_message)
        order.status = 'payment_failed'
        db_session.commit()
        return {'success': False, 'error': e.user_message}
    except stripe.error.StripeError as e:
        log.error('Stripe error for order %d: %s', order_id, e)
        return {'success': False, 'error': 'Payment service unavailable'}

    order.payment_id = charge.id
    order.status = 'paid'
    db_session.commit()
    return {'success': True, 'payment_id': charge.id}
